    <script>
        const bubbleChartDiv = document.getElementById('bubbleChart');
        const mergeChartDiv = document.getElementById('mergeChart');
        const quickChartDiv = document.getElementById('quickChart');

        const bubbleStepsSpan = document.getElementById('bubbleSteps');
        const mergeStepsSpan = document.getElementById('mergeSteps');
        const quickStepsSpan = document.getElementById('quickSteps');

        const startBtn = document.getElementById('startBtn');
        const resetBtn = document.getElementById('resetBtn');
        const arraySizeSelect = document.getElementById('arraySize');
        const animationSpeedSelect = document.getElementById('animationSpeed');

        let originalArray = [];
        let animationDelay = 50; // Milliseconds
        let arraySize = 25;
        let isSorting = false;

        // --- Visualization Utilities ---
        function createBars(container, arr) {
            container.innerHTML = '';
            const maxVal = Math.max(...arr);
            arr.forEach(val => {
                const bar = document.createElement('div');
                bar.classList.add('bar');
                bar.style.height = `${(val / maxVal) * 100}%`;
                bar.style.backgroundColor = '#4CAF50'; // Default green
                container.appendChild(bar);
            });
        }

        function updateBars(container, arr, currentIndices = [], swapIndices = [], sortedIndices = []) {
            const bars = container.children;
            const maxVal = Math.max(...originalArray); // Use max of original for consistent scaling
            for (let i = 0; i < arr.length; i++) {
                const bar = bars[i];
                if (bar) { // Check if bar exists
                    bar.style.height = `${(arr[i] / maxVal) * 100}%`;
                    bar.classList.remove('comparing', 'swapping', 'sorted');

                    if (sortedIndices.includes(i)) {
                        bar.classList.add('sorted');
                    } else if (swapIndices.includes(i)) {
                        bar.classList.add('swapping');
                    } else if (currentIndices.includes(i)) {
                        bar.classList.add('comparing');
                    } else {
                         bar.style.backgroundColor = '#4CAF50'; // Default green if not highlighted
                    }
                }
            }
        }

        function resetCharts() {
            isSorting = false;
            generateNewArray();
            createBars(bubbleChartDiv, originalArray);
            createBars(mergeChartDiv, originalArray);
            createBars(quickChartDiv, originalArray);
            bubbleStepsSpan.textContent = '0';
            mergeStepsSpan.textContent = '0';
            quickStepsSpan.textContent = '0';
            startBtn.disabled = false;
        }

        function generateNewArray() {
            arraySize = parseInt(arraySizeSelect.value);
            originalArray = Array.from({ length: arraySize }, (_, i) => i + 1)
                                .sort(() => Math.random() - 0.5); // Shuffle
        }

        // --- Event Listeners ---
        startBtn.addEventListener('click', async () => {
            if (isSorting) return;
            isSorting = true;
            startBtn.disabled = true;

            animationDelay = parseInt(animationSpeedSelect.value);

            const arrBubble = [...originalArray];
            const arrMerge = [...originalArray];
            const arrQuick = [...originalArray];

            // Use Promise.all to run animations concurrently, but only if delay is not 0
            if (animationDelay > 0) {
                await Promise.all([
                    bubbleSortVisualize(arrBubble, bubbleChartDiv, bubbleStepsSpan),
                    mergeSortVisualize(arrMerge, mergeChartDiv, mergeStepsSpan),
                    quickSortVisualize(arrQuick, quickChartDiv, quickStepsSpan)
                ]);
            } else { // If instant, just run the sorts without delays
                bubbleSortVisualize(arrBubble, bubbleChartDiv, bubbleStepsSpan);
                mergeSortVisualize(arrMerge, mergeChartDiv, mergeStepsSpan);
                quickSortVisualize(arrQuick, quickChartDiv, quickStepsSpan);
            }

            isSorting = false;
            startBtn.disabled = false;
        });

        resetBtn.addEventListener('click', resetCharts);
        arraySizeSelect.addEventListener('change', resetCharts);
        animationSpeedSelect.addEventListener('change', () => {
             animationDelay = parseInt(animationSpeedSelect.value);
        });


        // --- Sorting Algorithms with Visualization Hooks ---

        // Helper for delay
        const delay = (ms) => new Promise(res => setTimeout(res, ms));

        // Bubble Sort
        async function bubbleSortVisualize(arr, chartContainer, stepsSpan) {
            let n = arr.length;
            let steps = 0;
            for (let i = 0; i < n - 1; i++) {
                let swapped = false;
                for (let j = 0; j < n - 1 - i; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    updateBars(chartContainer, arr, [j, j + 1]); // Highlight comparing elements
                    if (animationDelay > 0) await delay(animationDelay);

                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                        swapped = true;
                        updateBars(chartContainer, arr, [], [j, j + 1]); // Highlight swapped elements
                        if (animationDelay > 0) await delay(animationDelay);
                    }
                }
                if (!swapped) break; // Optimization: if no swaps, array is sorted
                // Mark the last element of the current pass as sorted
                updateBars(chartContainer, arr, [], [], Array.from({ length: i + 1 }, (_, k) => n - 1 - k));
            }
            // Mark all elements as sorted at the end
            updateBars(chartContainer, arr, [], [], Array.from({ length: n }, (_, k) => k));
        }

        // Merge Sort
        async function mergeSortVisualize(arr, chartContainer, stepsSpan) {
            let steps = 0;
            const auxiliaryArray = Array(arr.length); // For merge operations

            async function mergeSort(mainArray, startIdx, endIdx) {
                if (startIdx === endIdx) return;

                const middleIdx = Math.floor((startIdx + endIdx) / 2);
                await mergeSort(mainArray, startIdx, middleIdx);
                await mergeSort(mainArray, middleIdx + 1, endIdx);
                await merge(mainArray, startIdx, middleIdx, endIdx);
            }

            async function merge(mainArray, startIdx, middleIdx, endIdx) {
                let i = startIdx;
                let j = middleIdx + 1;
                let k = startIdx;

                // Copy relevant part to auxiliary array
                for (let x = startIdx; x <= endIdx; x++) {
                    auxiliaryArray[x] = mainArray[x];
                }

                while (i <= middleIdx && j <= endIdx) {
                    steps++;
                    stepsSpan.textContent = steps;
                    updateBars(chartContainer, mainArray, [i, j]);
                    if (animationDelay > 0) await delay(animationDelay);

                    if (auxiliaryArray[i] <= auxiliaryArray[j]) {
                        mainArray[k++] = auxiliaryArray[i++];
                    } else {
                        mainArray[k++] = auxiliaryArray[j++];
                    }
                    updateBars(chartContainer, mainArray, [], [k - 1]); // Show element being placed
                    if (animationDelay > 0) await delay(animationDelay);
                }

                while (i <= middleIdx) {
                    steps++;
                    stepsSpan.textContent = steps;
                    mainArray[k++] = auxiliaryArray[i++];
                    updateBars(chartContainer, mainArray, [], [k - 1]);
                    if (animationDelay > 0) await delay(animationDelay);
                }

                while (j <= endIdx) {
                    steps++;
                    stepsSpan.textContent = steps;
                    mainArray[k++] = auxiliaryArray[j++];
                    updateBars(chartContainer, mainArray, [], [k - 1]);
                    if (animationDelay > 0) await delay(animationDelay);
                }

                // After merge, update the entire merged section to show its state
                updateBars(chartContainer, mainArray, [], [], Array.from({ length: endIdx - startIdx + 1 }, (_, x) => startIdx + x));
                if (animationDelay > 0) await delay(animationDelay);
            }

            await mergeSort(arr, 0, arr.length - 1);
            updateBars(chartContainer, arr, [], [], Array.from({ length: arr.length }, (_, k) => k)); // Mark all sorted
        }

        // Quick Sort
        async function quickSortVisualize(arr, chartContainer, stepsSpan) {
            let steps = 0;

            async function partition(mainArray, low, high) {
                let pivot = mainArray[high];
                let i = (low - 1);

                for (let j = low; j <= high - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    updateBars(chartContainer, mainArray, [j, high]); // Highlight current element and pivot
                    if (animationDelay > 0) await delay(animationDelay);

                    if (mainArray[j] < pivot) {
                        i++;
                        [mainArray[i], mainArray[j]] = [mainArray[j], mainArray[i]]; // Swap
                        updateBars(chartContainer, mainArray, [], [i, j]); // Highlight swapped elements
                        if (animationDelay > 0) await delay(animationDelay);
                    }
                }
                [mainArray[i + 1], mainArray[high]] = [mainArray[high], mainArray[i + 1]]; // Place pivot
                updateBars(chartContainer, mainArray, [], [i + 1, high]); // Highlight pivot placement
                if (animationDelay > 0) await delay(animationDelay);
                return i + 1;
            }

            async function quickSort(mainArray, low, high) {
                if (low < high) {
                    let pi = await partition(mainArray, low, high);
                    await quickSort(mainArray, low, pi - 1);
                    await quickSort(mainArray, pi + 1, high);
                }
            }

            await quickSort(arr, 0, arr.length - 1);
