        const bubbleSortChart = document.getElementById('bubbleSortChart');
        const mergeSortChart = document.getElementById('mergeSortChart');
        const quickSortChart = document.getElementById('quickSortChart');

        const bubbleSortStepsSpan = document.getElementById('bubbleSortSteps');
        const mergeSortStepsSpan = document.getElementById('mergeSortSteps');
        const quickSortStepsSpan = document.getElementById('quickSortSteps');

        let arraySize = parseInt(arraySizeSlider.value);
        let animationSpeed = parseInt(animationSpeedSlider.value); // In milliseconds
        let originalArray = [];
        let isSorting = false;
        let timeouts = [];

        // Update slider values
        arraySizeSlider.oninput = () => {
            arraySize = parseInt(arraySizeSlider.value);
            arraySizeValueSpan.textContent = arraySize;
            if (!isSorting) {
                resetAndGenerateNewData();
            }
        };

        animationSpeedSlider.oninput = () => {
            animationSpeed = parseInt(animationSpeedSpeedSlider.value);
            animationSpeedValueSpan.textContent = animationSpeed;
        };

        startButton.onclick = () => {
            if (!isSorting) {
                startSorting();
            }
        };

        resetButton.onclick = () => {
            stopSorting();
            resetAndGenerateNewData();
        };

        function generateRandomArray(size) {
            const arr = [];
            for (let i = 0; i < size; i++) {
                arr.push(Math.floor(Math.random() * (200 - 20 + 1)) + 20); // Values between 20 and 200
            }
            return arr;
        }

        function renderChart(container, array, highlightIndices = [], highlightClass = '', pivotIndex = -1, sortedIndices = []) {
            container.innerHTML = '';
            const barWidth = (100 / array.length) - 0.2; // Adjust for margin
            array.forEach((value, index) => {
                const bar = document.createElement('div');
                bar.classList.add('bar');
                bar.style.height = `${value}px`;
                bar.style.setProperty('--bar-width', `${barWidth}%`);

                if (sortedIndices.includes(index)) {
                    bar.classList.add('sorted');
                } else if (pivotIndex === index) {
                    bar.classList.add('pivot');
                } else if (highlightIndices.includes(index)) {
                    bar.classList.add(highlightClass);
                }
                container.appendChild(bar);
            });
        }

        function resetAndGenerateNewData() {
            originalArray = generateRandomArray(arraySize);
            renderChart(bubbleSortChart, originalArray);
            renderChart(mergeSortChart, originalArray);
            renderChart(quickSortChart, originalArray);
            bubbleSortStepsSpan.textContent = 0;
            mergeSortStepsSpan.textContent = 0;
            quickSortStepsSpan.textContent = 0;
            startButton.disabled = false;
        }

        function stopSorting() {
            isSorting = false;
            timeouts.forEach(clearTimeout);
            timeouts = [];
        }

        async function startSorting() {
            if (isSorting) return;
            isSorting = true;
            startButton.disabled = true;

            const arr1 = [...originalArray];
            const arr2 = [...originalArray];
            const arr3 = [...originalArray];

            const bubbleSortPromise = visualizeBubbleSort(arr1, bubbleSortChart, bubbleSortStepsSpan);
            const mergeSortPromise = visualizeMergeSort(arr2, mergeSortChart, mergeSortStepsSpan);
            const quickSortPromise = visualizeQuickSort(arr3, quickSortChart, quickSortStepsSpan);

            await Promise.all([bubbleSortPromise, mergeSortPromise, quickSortPromise]);

            isSorting = false;
            startButton.disabled = false;
        }

        // --- Sorting Algorithms with Visualization ---

        // Bubble Sort
        async function visualizeBubbleSort(arr, chartContainer, stepsSpan) {
            let n = arr.length;
            let steps = 0;
            let sortedCount = 0;

            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;

                    renderChart(chartContainer, arr, [j, j + 1], 'comparing', -1, Array.from({length: sortedCount}, (_, k) => n - 1 - k));
                    await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                    if (arr[j] > arr[j + 1]) {
                        renderChart(chartContainer, arr, [j, j + 1], 'swapping', -1, Array.from({length: sortedCount}, (_, k) => n - 1 - k));
                        await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                    }
                }
                sortedCount++;
            }
            // Final render with all sorted
            renderChart(chartContainer, arr, [], '', -1, Array.from({length: n}, (_, k) => k));
        }

        // Merge Sort
        async function visualizeMergeSort(arr, chartContainer, stepsSpan) {
            let steps = 0;

            async function merge(left, right) {
                let resultArray = [], leftIndex = 0, rightIndex = 0;

                while (leftIndex < left.length && rightIndex < right.length) {
                    steps++;
                    stepsSpan.textContent = steps;
                    if (left[leftIndex] < right[rightIndex]) {
                        resultArray.push(left[leftIndex]);
                        leftIndex++;
                    } else {
                        resultArray.push(right[rightIndex]);
                        rightIndex++;
                    }
                }
                return resultArray.concat(left.slice(leftIndex)).concat(right.slice(rightIndex));
            }

            async function mergeSortRecursive(currentArr, start, end) {
                if (currentArr.length <= 1) {
                    return currentArr;
                }

                const middle = Math.floor(currentArr.length / 2);
                const left = currentArr.slice(0, middle);
                const right = currentArr.slice(middle);

                const sortedLeft = await mergeSortRecursive(left, start, start + middle - 1);
                const sortedRight = await mergeSortRecursive(right, start + middle, end);

                const merged = await merge(sortedLeft, sortedRight);

                // Update the main array for visualization
                for (let i = 0; i < merged.length; i++) {
                    arr[start + i] = merged[i];
                }

                // Highlight the merged section
                renderChart(chartContainer, arr, Array.from({length: merged.length}, (_, i) => start + i), 'selected');
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                return merged;
            }

            await mergeSortRecursive(arr, 0, arr.length - 1);
            // Final render with all sorted
            renderChart(chartContainer, arr, [], '', -1, Array.from({length: arr.length}, (_, k) => k));
        }


        // Quick Sort
        async function visualizeQuickSort(arr, chartContainer, stepsSpan) {
            let steps = 0;

            async function partition(low, high) {
                let pivot = arr[high];
                let i = (low - 1);

                renderChart(chartContainer, arr, [], '', high); // Highlight pivot
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                for (let j = low; j <= high - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderChart(chartContainer, arr, [j], 'comparing', high);
                    await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                    if (arr[j] < pivot) {
                        i++;
                        renderChart(chartContainer, arr, [i, j], 'swapping', high);
                        await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));
                        [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                    }
                }
                renderChart(chartContainer, arr, [i + 1, high], 'swapping', high);
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));
                [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]]; // Swap pivot to correct position

                return (i + 1);
            }

            async function quickSortRecursive(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);

                    await quickSortRecursive(low, pi - 1);
                    await quickSortRecursive(pi + 1, high);
                }
            }

            await quickSortRecursive(0, arr.length - 1);
            // Final render with all sorted
            renderChart(chartContainer, arr, [], '', -1, Array.from({length: arr.length}, (_, k) => k));
        }

        // Initial setup
        resetAndGenerateNewData();

    </script>
</body>
