    </style>
</head>
<body>
    <h1>Sorting Algorithm Visualizer: A Performance Showdown</h1>

    <div class="intro">
        <p>This tool demonstrates the performance differences between common sorting algorithms. Observe Bubble Sort, a simple but often inefficient algorithm, against Insertion Sort and Merge Sort, which offer better performance characteristics, especially on larger datasets.</p>
        <p>Click "Start Sorting" to see them in action on the same randomized data!</p>
    </div>

    <div class="controls">
        <button id="startButton">Start Sorting</button>
        <button id="resetButton">Reset Data</button>
    </div>

    <div class="container">
        <!-- Bubble Sort Card -->
        <div class="algorithm-card">
            <h2>Bubble Sort</h2>
            <canvas id="bubbleSortCanvas" width="300" height="200"></canvas>
            <div class="step-counter" id="bubbleSortSteps">Steps: 0</div>
            <div class="explanation">
                <strong>Time Complexity: O(N²)</strong><br>
                Bubble Sort repeatedly steps through the list, compares adjacent elements and swaps them if they are in the wrong order. The pass through the list is repeated until no swaps are needed, which indicates that the list is sorted. It's simple but very inefficient for large datasets.
            </div>
        </div>

        <!-- Insertion Sort Card -->
        <div class="algorithm-card">
            <h2>Insertion Sort</h2>
            <canvas id="insertionSortCanvas" width="300" height="200"></canvas>
            <div class="step-counter" id="insertionSortSteps">Steps: 0</div>
            <div class="explanation">
                <strong>Time Complexity: O(N²) (Worst/Average), O(N) (Best)</strong><br>
                Insertion Sort builds the final sorted array one item at a time. It iterates through the input elements and "inserts" each element into its correct position in the already sorted part of the array. It's efficient for small datasets or nearly sorted data.
            </div>
        </div>

        <!-- Merge Sort Card -->
        <div class="algorithm-card">
            <h2>Merge Sort</h2>
            <canvas id="mergeSortCanvas" width="300" height="200"></canvas>
            <div class="step-counter" id="mergeSortSteps">Steps: 0</div>
            <div class="explanation">
                <strong>Time Complexity: O(N log N)</strong><br>
                Merge Sort is a "divide and conquer" algorithm. It recursively divides the array into halves until it gets to single-element arrays (which are inherently sorted). Then, it repeatedly merges them back together, sorting them in the process. It's very efficient for large datasets.
            </div>
        </div>
    </div>

    <script>
        const ARRAY_SIZE = 50; // Number of bars to sort
        const ANIMATION_SPEED = 10; // Milliseconds per step (lower is faster)
        const BAR_COLOR = '#4a90e2';
        const HIGHLIGHT_COLOR = '#e74c3c'; // For comparing/swapping
        const SORTED_COLOR = '#2ecc71'; // For elements that are in final sorted position

        let originalData = [];
        let dataBubble = [];
        let dataInsertion = [];
        let dataMerge = [];

        let bubbleSortSteps = 0;
        let insertionSortSteps = 0;
        let mergeSortSteps = 0;

        let bubbleSortRunning = false;
        let insertionSortRunning = false;
        let mergeSortRunning = false;

        let bubbleSortFinished = false;
        let insertionSortFinished = false;
        let mergeSortFinished = false;

        const bubbleCanvas = document.getElementById('bubbleSortCanvas');
        const insertionCanvas = document.getElementById('insertionSortCanvas');
        const mergeCanvas = document.getElementById('mergeSortCanvas');

        const bubbleCtx = bubbleCanvas.getContext('2d');
        const insertionCtx = insertionCanvas.getContext('2d');
        const mergeCtx = mergeCanvas.getContext('2d');

        const bubbleStepsEl = document.getElementById('bubbleSortSteps');
        const insertionStepsEl = document.getElementById('insertionSortSteps');
        const mergeStepsEl = document.getElementById('mergeSortSteps');

        const startButton = document.getElementById('startButton');
        const resetButton = document.getElementById('resetButton');

        // --- Utility Functions ---
        function generateRandomData(size) {
            const arr = [];
            for (let i = 0; i < size; i++) {
                arr.push(Math.floor(Math.random() * (bubbleCanvas.height - 20)) + 10); // Values between 10 and height-10
            }
            return arr;
        }

        function drawBars(ctx, data, highlightIndices = [], sortedIndices = []) {
            const barWidth = ctx.canvas.width / data.length;
            ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);

            for (let i = 0; i < data.length; i++) {
                const barHeight = data[i];
                const x = i * barWidth;
                const y = ctx.canvas.height - barHeight;

                if (highlightIndices.includes(i)) {
                    ctx.fillStyle = HIGHLIGHT_COLOR;
                } else if (sortedIndices.includes(i)) {
                    ctx.fillStyle = SORTED_COLOR;
                } else {
                    ctx.fillStyle = BAR_COLOR;
                }
                ctx.fillRect(x, y, barWidth - 1, barHeight); // -1 for a small gap
            }
        }

        function updateStepCounter(element, steps) {
            element.textContent = `Steps: ${steps}`;
        }

        function resetState() {
            originalData = generateRandomData(ARRAY_SIZE);
            dataBubble = [...originalData];
            dataInsertion = [...originalData];
            dataMerge = [...originalData];

            bubbleSortSteps = 0;
            insertionSortSteps = 0;
            mergeSortSteps = 0;

            bubbleSortRunning = false;
            insertionSortRunning = false;
            mergeSortRunning = false;

            bubbleSortFinished = false;
            insertionSortFinished = false;
            mergeSortFinished = false;

            updateStepCounter(bubbleStepsEl, 0);
            updateStepCounter(insertionStepsEl, 0);
            updateStepCounter(mergeStepsEl, 0);

            drawBars(bubbleCtx, dataBubble);
            drawBars(insertionCtx, dataInsertion);
            drawBars(mergeCtx, dataMerge);

            startButton.disabled = false;
        }

        // --- Sorting Algorithms ---

        // Bubble Sort
        async function bubbleSort(arr, ctx, stepCounterEl) {
            bubbleSortRunning = true;
            let n = arr.length;
            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    if (!bubbleSortRunning) return; // Stop if reset
                    bubbleSortSteps++;
                    updateStepCounter(stepCounterEl, bubbleSortSteps);

                    drawBars(ctx, arr, [j, j + 1]);
                    await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));

                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                        drawBars(ctx, arr, [j, j + 1]); // Show swap
                        await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
                    }
                }
                if (!bubbleSortRunning) return;
                // Mark the largest element of this pass as sorted
                let sortedIndices = Array.from({length: i + 1}, (v, k) => n - 1 - k);
                drawBars(ctx, arr, [], sortedIndices);
            }
            if (bubbleSortRunning) { // Only mark finished if not stopped by reset
                bubbleSortFinished = true;
                drawBars(ctx, arr, [], Array.from({length: n}, (v, k) => k)); // All sorted
                checkAllFinished();
            }
        }

        // Insertion Sort
        async function insertionSort(arr, ctx, stepCounterEl) {
            insertionSortRunning = true;
            let n = arr.length;
            for (let i = 1; i < n; i++) {
                if (!insertionSortRunning) return;
                let current = arr[i];
                let j = i - 1;

                drawBars(ctx, arr, [i]);
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));

                while (j >= 0 && arr[j] > current) {
                    if (!insertionSortRunning) return;
                    insertionSortSteps++;
                    updateStepCounter(stepCounterEl, insertionSortSteps);

                    arr[j + 1] = arr[j];
                    drawBars(ctx, arr, [j, j + 1]); // Show shift
                    await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
                    j--;
                }
                arr[j + 1] = current;
                drawBars(ctx, arr, [j + 1]); // Show insertion
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));

                // Mark elements up to i as sorted (conceptually, not necessarily physically locked)
                let sortedIndices = Array.from({length: i + 1}, (v, k) => k);
                drawBars(ctx, arr, [], sortedIndices);
            }
            if (insertionSortRunning) {
                insertionSortFinished = true;
                drawBars(ctx, arr, [], Array.from({length: n}, (v, k) => k)); // All sorted
                checkAllFinished();
            }
        }

        // Merge Sort (Recursive, needs helper to animate)
        async function mergeSortWrapper(arr, ctx, stepCounterEl) {
            mergeSortRunning = true;
            await mergeSortRecursive(arr, 0, arr.length - 1, ctx, stepCounterEl);
            if (mergeSortRunning) {
                mergeSortFinished = true;
                drawBars(ctx, arr, [], Array.from({length: arr.length}, (v, k) => k)); // All sorted
                checkAllFinished();
            }
        }

        async function mergeSortRecursive(arr, l, r, ctx, stepCounterEl) {
            if (!mergeSortRunning) return;
            if (l >= r) {
                return;
            }
            const m = Math.floor((l + r) / 2);
            await mergeSortRecursive(arr, l, m, ctx, stepCounterEl);
            if (!mergeSortRunning) return;
            await mergeSortRecursive(arr, m + 1, r, ctx, stepCounterEl);
            if (!mergeSortRunning) return;
            await merge(arr, l, m, r, ctx, stepCounterEl);
        }

        async function merge(arr, l, m, r, ctx, stepCounterEl) {
            if (!mergeSortRunning) return;
            const n1 = m - l + 1;
            const n2 = r - m;

            let L = new Array(n1);
            let R = new Array(n2);

            for (let i = 0; i < n1; i++)
                L[i] = arr[l + i];
            for (let j = 0; j < n2; j++)
                R[j] = arr[m + 1 + j];

            let i = 0;
            let j = 0;
            let k = l;

            while (i < n1 && j < n2) {
                if (!mergeSortRunning) return;
                mergeSortSteps++;
                updateStepCounter(stepCounterEl, mergeSortSteps);
                drawBars(ctx, arr, [l + i, m + 1 + j]); // Highlight elements being compared
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));

                if (L[i] <= R[j]) {
                    arr[k] = L[i];
                    i++;
                } else {
                    arr[k] = R[j];
                    j++;
                }
                drawBars(ctx, arr, [k]); // Highlight element placed
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
                k++;
            }

            while (i < n1) {
                if (!mergeSortRunning) return;
                mergeSortSteps++;
                updateStepCounter(stepCounterEl, mergeSortSteps);
                arr[k] = L[i];
                drawBars(ctx, arr, [k]);
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
                i++;
                k++;
            }

            while (j < n2) {
                if (!mergeSortRunning) return;
                mergeSortSteps++;
                updateStepCounter(stepCounterEl, mergeSortSteps);
                arr[k] = R[j];
                drawBars(ctx, arr, [k]);
                await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
                j++;
                k++;
            }
            // After merging a segment, show its sorted state
            let sortedIndices = Array.from({length: r - l + 1}, (v, idx) => l + idx);
            drawBars(ctx, arr, [], sortedIndices);
            await new Promise(resolve => setTimeout(resolve, ANIMATION_SPEED));
        }


        function checkAllFinished() {
            if (bubbleSortFinished && insertionSortFinished && mergeSortFinished) {
                startButton.disabled = true; // All finished, disable start button
            }
        }

        // --- Event Listeners ---
        startButton.addEventListener('click', () => {
            startButton.disabled = true;
            bubbleSort(dataBubble, bubbleCtx, bubbleStepsEl);
            insertionSort(dataInsertion, insertionCtx, insertionStepsEl);
            mergeSortWrapper(dataMerge, mergeCtx, mergeStepsEl);
        });

        resetButton.addEventListener('click', () => {
            bubbleSortRunning = false;
            insertionSortRunning = false;
            mergeSortRunning = false;
            // A small delay to allow any pending animation frames to clear
            setTimeout(resetState, ANIMATION_SPEED * 2);
        });

        // Initialize on load
        window.onload = resetState;

    </script>
</body>
</html>
