    <div class="explanation">
        <h2>Understanding Time Complexities</h2>
        <p>Time complexity describes how the runtime of an algorithm scales with the input size (<span class="notation">n</span>). It's typically expressed using Big O notation, which focuses on the upper bound of the growth rate.</p>
        <ul>
            <li>
                <h3><span class="notation">O(n²)</span> - Quadratic Time (e.g., Bubble Sort)</h3>
                <p>This means that if you double the input size, the number of operations (and thus the time) will roughly quadruple. For a list of 100 items, it might take 10,000 operations. For 1000 items, it's 1,000,000 operations. This growth is very steep and quickly becomes impractical for large datasets.</p>
            </li>
            <li>
                <h3><span class="notation">O(n log n)</span> - Log-Linear Time (e.g., Merge Sort, Quick Sort average)</h3>
                <p>This is significantly better than <span class="notation">O(n²)</span>. If you double the input size, the number of operations roughly doubles, but with an additional logarithmic factor. For 100 items, it might be around 700 operations. For 1000 items, it's about 10,000 operations. This scales much more gracefully, making these algorithms suitable for large datasets.</p>
            </li>
            <li>
                <h3><span class="notation">O(n)</span> - Linear Time (e.g., Bubble Sort best case)</h3>
                <p>The best case for Bubble Sort occurs when the array is already sorted. In this scenario, it only needs to make one pass to confirm it's sorted, performing <span class="notation">n</span> comparisons. This means the time grows directly proportional to the input size. However, this is rarely the case in practice for unsorted data.</p>
            </li>
        </ul>
        <p>As you can see from the visualization, Bubble Sort's <span class="notation">O(n²)</span> average-case complexity means it falls far behind Merge Sort and Quick Sort as the number of elements (<span class="notation">n</span>) increases, making it a poor choice for general-purpose sorting.</p>
    </div>

    <script>
        const dataSizeSlider = document.getElementById('dataSize');
        const dataSizeValueSpan = document.getElementById('dataSizeValue');
        const animationSpeedSlider = document.getElementById('animationSpeed');
        const animationSpeedValueSpan = document.getElementById('animationSpeedValue');
        const startButton = document.getElementById('startButton');
        const resetButton = document.getElementById('resetButton');
        const randomizeButton = document.getElementById('randomizeButton');

        const bubbleSortChart = document.getElementById('bubbleSortChart');
        const mergeSortChart = document.getElementById('mergeSortChart');
        const quickSortChart = document.getElementById('quickSortChart');

        const bubbleSortStepsSpan = document.getElementById('bubbleSortSteps');
        const mergeSortStepsSpan = document.getElementById('mergeSortSteps');
        const quickSortStepsSpan = document.getElementById('quickSortSteps');

        let originalData = [];
        let animationDelay = 50; // ms
        let dataSize = 50;
        let isSorting = false;
        let animationFrames = []; // To store animation frame IDs for clearing

        // --- Utility Functions ---
        function generateRandomData(size) {
            const data = [];
            for (let i = 0; i < size; i++) {
                data.push(Math.floor(Math.random() * 190) + 10); // Values between 10 and 200
            }
            return data;
        }

        function renderBars(container, data, highlightIndices = [], highlightType = '') {
            container.innerHTML = '';
            const maxHeight = 200; // Chart height
            const maxVal = Math.max(...originalData); // Use originalData's max for consistent scaling

            data.forEach((val, index) => {
                const bar = document.createElement('div');
                bar.classList.add('bar');
                bar.style.height = `${(val / maxVal) * maxHeight}px`;

                if (highlightIndices.includes(index)) {
                    bar.classList.add(highlightType);
                }
                container.appendChild(bar);
            });
        }

        function resetCharts() {
            bubbleSortStepsSpan.textContent = '0';
            mergeSortStepsSpan.textContent = '0';
            quickSortStepsSpan.textContent = '0';
            renderBars(bubbleSortChart, originalData);
            renderBars(mergeSortChart, originalData);
            renderBars(quickSortChart, originalData);
            isSorting = false;
            startButton.disabled = false;
            randomizeButton.disabled = false;
            dataSizeSlider.disabled = false;
        }

        function updateSliderValues() {
            dataSize = parseInt(dataSizeSlider.value);
            dataSizeValueSpan.textContent = dataSize;
            animationDelay = parseInt(animationSpeedSlider.value);
            animationSpeedValueSpan.textContent = animationDelay;
        }

        function initialize() {
            updateSliderValues();
            originalData = generateRandomData(dataSize);
            resetCharts();
        }

        // --- Sorting Algorithms ---

        // Bubble Sort
        async function bubbleSort(arr, chartContainer, stepsSpan) {
            const n = arr.length;
            let steps = 0;
            let currentArr = [...arr];

            for (let i = 0; i < n - 1; i++) {
                let swapped = false;
                for (let j = 0; j < n - 1 - i; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderBars(chartContainer, currentArr, [j, j + 1], 'comparing');
                    await new Promise(resolve => setTimeout(resolve, animationDelay));

                    if (currentArr[j] > currentArr[j + 1]) {
                        [currentArr[j], currentArr[j + 1]] = [currentArr[j + 1], currentArr[j]];
                        swapped = true;
                        renderBars(chartContainer, currentArr, [j, j + 1], 'swapping');
                        await new Promise(resolve => setTimeout(resolve, animationDelay));
                    }
                }
                // Mark the largest element of this pass as sorted
                renderBars(chartContainer, currentArr, Array.from({ length: i + 1 }, (_, k) => n - 1 - k), 'sorted');
                if (!swapped) break; // Optimization: If no two elements were swapped, array is sorted
            }
            renderBars(chartContainer, currentArr, Array.from({ length: n }, (_, k) => k), 'sorted'); // Mark all as sorted
        }

        // Merge Sort
        async function mergeSort(arr, chartContainer, stepsSpan) {
            let steps = 0;
            let currentArr = [...arr]; // Create a copy to modify
            let tempArray = new Array(arr.length); // Auxiliary array for merging

            async function merge(low, mid, high) {
                for (let k = low; k <= high; k++) {
                    tempArray[k] = currentArr[k];
                }

                let i = low, j = mid + 1;
                for (let k = low; k <= high; k++) {
                    steps++;
                    stepsSpan.textContent = steps;

                    if (i > mid) {
                        currentArr[k] = tempArray[j++];
                    } else if (j > high) {
                        currentArr[k] = tempArray[i++];
                    } else if (tempArray[j] < tempArray[i]) {
                        currentArr[k] = tempArray[j++];
                    } else {
                        currentArr[k] = tempArray[i++];
                    }
                    renderBars(chartContainer, currentArr, Array.from({ length: high - low + 1 }, (_, idx) => low + idx), 'comparing');
                    await new Promise(resolve => setTimeout(resolve, animationDelay));
                }
            }

            async function sort(low, high) {
                if (high <= low) return;
                let mid = Math.floor(low + (high - low) / 2);
                await sort(low, mid);
                await sort(mid + 1, high);
                await merge(low, mid, high);
            }

            await sort(0, currentArr.length - 1);
            renderBars(chartContainer, currentArr, Array.from({ length: arr.length }, (_, k) => k), 'sorted'); // Mark all as sorted
        }

        // Quick Sort
        async function quickSort(arr, chartContainer, stepsSpan) {
            let steps = 0;
            let currentArr = [...arr];

            async function partition(low, high) {
                let pivot = currentArr[high];
                let i = (low - 1);

                for (let j = low; j <= high - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderBars(chartContainer, currentArr, [j, high], 'comparing'); // Highlight current element and pivot
                    await new Promise(resolve => setTimeout(resolve, animationDelay));

                    if (currentArr[j] < pivot) {
                        i++;
                        [currentArr[i], currentArr[j]] = [currentArr[j], currentArr[i]];
                        renderBars(chartContainer, currentArr, [i, j], 'swapping'); // Highlight swapped elements
                        await new Promise(resolve => setTimeout(resolve, animationDelay));
                    }
                }
                [currentArr[i + 1], currentArr[high]] = [currentArr[high], currentArr[i + 1]];
                renderBars(chartContainer, currentArr, [i + 1, high], 'swapping'); // Highlight pivot swap
                await new Promise(resolve => setTimeout(resolve, animationDelay));
                return i + 1;
            }

            async function sort(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);
                    await sort(low, pi - 1);
                    await sort(pi + 1, high);
                }
                // Mark sorted segments after recursive calls
                if (high - low + 1 > 1) { // Only mark as sorted if it's a segment larger than 1
                   renderBars(chartContainer, currentArr, Array.from({ length: high - low + 1 }, (_, k) => low + k), 'sorted');
                   await new Promise(resolve => setTimeout(resolve, animationDelay));
                }
            }

            await sort(0, currentArr.length - 1);
            renderBars(chartContainer, currentArr, Array.from({ length: arr.length }, (_, k) => k), 'sorted'); // Final mark all as sorted
        }


        // --- Event Listeners ---
        dataSizeSlider.addEventListener('input', () => {
            if (!isSorting) {
                updateSliderValues();
                originalData = generateRandomData(dataSize);
                resetCharts();
            }
        });

        animationSpeedSlider.addEventListener('input', updateSliderValues);

        randomizeButton.addEventListener('click', () => {
            if (!isSorting) {
                originalData = generateRandomData(dataSize);
                resetCharts();
            }
        });

        startButton.addEventListener('click', async () => {
            if (isSorting) return;
            isSorting = true;
            startButton.disabled = true;
            randomizeButton.disabled = true;
            dataSizeSlider.disabled = true;

            // Clear any previous animation frames (though not strictly needed with async/await)
            animationFrames.forEach(clearTimeout);
            animationFrames = [];

            // Reset step counters and render initial state
            resetCharts(); // This will re-render with originalData and reset steps

            // Start sorting concurrently
            const bubblePromise = bubbleSort(originalData, bubbleSortChart, bubbleSortStepsSpan);
            const mergePromise = mergeSort(originalData, mergeSortChart, mergeSortStepsSpan);
            const quickPromise = quickSort(originalData, quickSortChart, quickSortStepsSpan);

            await Promise.all([bubblePromise, mergePromise, quickPromise]);

            isSorting = false;
            startButton.disabled = false;
            randomizeButton.disabled = false;
            dataSizeSlider.disabled = false;
        });

        resetButton.addEventListener('click', () => {
            if (isSorting) {
                // In a real application, you might need to implement a way to stop ongoing async sorts
                // For this simple demo, we'll just allow reset to re-initialize
                // and assume ongoing sorts will finish or naturally stop when elements are sorted.
            }
            initialize();
        });

        // Initialize on load
        initialize();

    </script>
</body>
</html>
