                sortingActive = false;
                startButton.disabled = true; // All sorted, cannot restart without reset
                dataSizeInput.disabled = false;
            }
        }

        // --- Sorting Algorithms (Generators for animation) ---

        // Bubble Sort
        function* bubbleSort(arr) {
            let n = arr.length;
            let sortedCount = 0;
            for (let i = 0; i < n - 1; i++) {
                let swapped = false;
                for (let j = 0; j < n - 1 - i; j++) {
                    yield { arr: [...arr], activeIndices: [j, j + 1], sortedIndices: Array.from({length: sortedCount}, (_,k) => n-1-k) }; // Highlight comparison
                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                        swapped = true;
                        yield { arr: [...arr], activeIndices: [j, j + 1], sortedIndices: Array.from({length: sortedCount}, (_,k) => n-1-k) }; // Highlight swap
                    }
                }
                sortedCount++; // One element is in its final place
                if (!swapped) break; // Optimization: if no two elements were swapped by inner loop, then array is sorted
            }
            yield { arr: [...arr], activeIndices: [], sortedIndices: Array.from({length: n}, (_,k) => k) }; // Final state
        }

        // Merge Sort
        function* mergeSort(arr) {
            const aux = [...arr];
            const sortedIndices = new Set();

            function* merge(low, mid, high) {
                let i = low;
                let j = mid + 1;
                for (let k = low; k <= high; k++) {
                    aux[k] = arr[k];
                }

                for (let k = low; k <= high; k++) {
                    if (i > mid) {
                        arr[k] = aux[j++];
                    } else if (j > high) {
                        arr[k] = aux[i++];
                    } else if (aux[j] < aux[i]) {
                        arr[k] = aux[j++];
                    } else {
                        arr[k] = aux[i++];
                    }
                    yield { arr: [...arr], activeIndices: [k], sortedIndices: Array.from(sortedIndices) };
                }
            }

            function* sort(low, high) {
                if (low >= high) return;
                const mid = Math.floor(low + (high - low) / 2);
                yield* sort(low, mid);
                yield* sort(mid + 1, high);
                yield* merge(low, mid, high);
            }

            yield* sort(0, arr.length - 1);
            for(let i=0; i<arr.length; i++) sortedIndices.add(i);
            yield { arr: [...arr], activeIndices: [], sortedIndices: Array.from(sortedIndices) }; // Final state
        }


        // Quick Sort
        function* quickSort(arr) {
            const sortedIndices = new Set(); // To track elements that are in their final sorted position

            function* partition(low, high) {
                const pivot = arr[high];
                let i = low - 1;

                for (let j = low; j < high; j++) {
                    yield { arr: [...arr], activeIndices: [j, high], sortedIndices: Array.from(sortedIndices) }; // Highlight comparison with pivot
                    if (arr[j] < pivot) {
                        i++;
                        [arr[i], arr[j]] = [arr[j], arr[i]];
                        yield { arr: [...arr], activeIndices: [i, j, high], sortedIndices: Array.from(sortedIndices) }; // Highlight swap
                    }
                }
                [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
                yield { arr: [...arr], activeIndices: [i + 1, high], sortedIndices: Array.from(sortedIndices) }; // Highlight pivot placement
                sortedIndices.add(i + 1); // Pivot is now in its final position
                return i + 1;
            }

            function* sort(low, high) {
                if (low < high) {
                    const pi = yield* partition(low, high);
                    yield* sort(low, pi - 1);
                    yield* sort(pi + 1, high);
                } else if (low === high) { // Single element is sorted
                    sortedIndices.add(low);
                    yield { arr: [...arr], activeIndices: [low], sortedIndices: Array.from(sortedIndices) };
                }
            }

            yield* sort(0, arr.length - 1);
            // Ensure all elements are marked as sorted at the very end
            for(let i=0; i<arr.length; i++) sortedIndices.add(i);
            yield { arr: [...arr], activeIndices: [], sortedIndices: Array.from(sortedIndices) }; // Final state
        }

        // Initialize on load
        document.addEventListener('DOMContentLoaded', resetData);

    </script>
</body>
</html>
