            <div id="selectionSortChart" class="chart-container"></div>
            <div id="selectionSortSteps" class="step-counter">Steps: 0</div>
        </div>

        <div class="algorithm-box">
            <h2>Merge Sort</h2>
            <div id="mergeSortChart" class="chart-container"></div>
            <div id="mergeSortSteps" class="step-counter">Steps: 0</div>
        </div>
    </div>

    <script>
        const numElementsInput = document.getElementById('numElements');
        const animationSpeedInput = document.getElementById('animationSpeed');
        const startSortButton = document.getElementById('startSort');

        const bubbleSortChart = document.getElementById('bubbleSortChart');
        const selectionSortChart = document.getElementById('selectionSortChart');
        const mergeSortChart = document.getElementById('mergeSortChart');

        const bubbleSortStepsCounter = document.getElementById('bubbleSortSteps');
        const selectionSortStepsCounter = document.getElementById('selectionSortSteps');
        const mergeSortStepsCounter = document.getElementById('mergeSortSteps');

        let animationDelay = 50; // Initial delay in ms
        let currentArraySize = 50;
        let animationRunning = false;
        let timeoutIds = [];

        function generateRandomArray(size) {
            const array = [];
            for (let i = 0; i < size; i++) {
                array.push(Math.floor(Math.random() * 190) + 10); // Values between 10 and 200
            }
            return array;
        }

        function renderChart(container, array, highlighted = [], sorted = []) {
            container.innerHTML = '';
            container.style.setProperty('--num-elements', array.length);
            const maxHeight = 200; // px
            const maxValue = 200; // Max value in our generated array

            array.forEach((value, index) => {
                const bar = document.createElement('div');
                bar.classList.add('bar');
                bar.style.height = `${(value / maxValue) * maxHeight}px`;

                if (highlighted.includes(index)) {
