                if (sorted.includes(index)) {
                    bar.classList.add('sorted');
                }
                container.appendChild(bar);
            });
        }

        function clearTimeouts() {
            timeoutIds.forEach(id => clearTimeout(id));
            timeoutIds = [];
        }

        async function bubbleSort(array, chartContainer, stepsCounter) {
            let arr = [...array];
            let n = arr.length;
            let steps = 0;
            let sortedIndices = [];

            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - 1 - i; j++) {
                    steps++;
                    renderChart(chartContainer, arr, [j, j + 1], sortedIndices);
                    stepsCounter.textContent = `Steps: ${steps}`;
                    await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay)));

                    if (arr[j] > arr[j + 1]) {
                        renderChart(chartContainer, arr, [j, j + 1], sortedIndices); // Re-render to show comparison before swap
                        stepsCounter.textContent = `Steps: ${steps}`;
                        await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2))); // Shorter delay for swap highlight

                        // Swap
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                        renderChart(chartContainer, arr, [j, j + 1], sortedIndices); // Show swapped elements
                        stepsCounter.textContent = `Steps: ${steps}`;
                        await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2)));
                    }
                }
                sortedIndices.push(n - 1 - i); // Mark the largest element as sorted
            }
            sortedIndices.push(0); // Mark the first element as sorted after the loop
            renderChart(chartContainer, arr, [], Array.from({length: n}, (_, i) => i)); // All sorted
            stepsCounter.textContent = `Steps: ${steps}`;
            return arr;
        }

        async function selectionSort(array, chartContainer, stepsCounter) {
            let arr = [...array];
            let n = arr.length;
            let steps = 0;
            let sortedIndices = [];

            for (let i = 0; i < n - 1; i++) {
                let minIndex = i;
                renderChart(chartContainer, arr, [i], sortedIndices); // Highlight current position
                stepsCounter.textContent = `Steps: ${steps}`;
                await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay)));

                for (let j = i + 1; j < n; j++) {
                    steps++;
                    renderChart(chartContainer, arr, [i, j, minIndex], sortedIndices); // Highlight current, comparing, and min
                    stepsCounter.textContent = `Steps: ${steps}`;
                    await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay)));

                    if (arr[j] < arr[minIndex]) {
                        minIndex = j;
                        renderChart(chartContainer, arr, [i, j, minIndex], sortedIndices); // Update min highlight
                        stepsCounter.textContent = `Steps: ${steps}`;
                        await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2)));
                    }
                }

                if (minIndex !== i) {
                    renderChart(chartContainer, arr, [i, minIndex], sortedIndices); // Highlight elements before swap
                    stepsCounter.textContent = `Steps: ${steps}`;
                    await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2)));

                    [arr[i], arr[minIndex]] = [arr[minIndex], arr[i]]; // Swap
                    renderChart(chartContainer, arr, [i, minIndex], sortedIndices); // Show swapped elements
                    stepsCounter.textContent = `Steps: ${steps}`;
                    await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2)));
                }
                sortedIndices.push(i); // Mark the element at current position as sorted
            }
            sortedIndices.push(n - 1); // Mark the last element as sorted
            renderChart(chartContainer, arr, [], Array.from({length: n}, (_, i) => i)); // All sorted
            stepsCounter.textContent = `Steps: ${steps}`;
            return arr;
        }

        async function mergeSort(array, chartContainer, stepsCounter) {
            let arr = [...array];
            let steps = 0;

            async function merge(left, right, originalStartIndex) {
                let result = [];
                let i = 0;
                let j = 0;

                while (i < left.length && j < right.length) {
                    steps++;
                    // Highlight elements being compared in the original array context
                    // This part is tricky with Merge Sort's recursive nature and visual representation
                    // For simplicity, we'll highlight the range being merged
                    let currentOriginalIndexLeft = originalStartIndex + i;
                    let currentOriginalIndexRight = originalStartIndex + left.length + j;
                    renderChart(chartContainer, arr, [currentOriginalIndexLeft, currentOriginalIndexRight]);
                    stepsCounter.textContent = `Steps: ${steps}`;
                    await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay / 2)));

                    if (left[i] < right[j]) {
                        result.push(left[i]);
                        i++;
                    } else {
                        result.push(right[j]);
                        j++;
                    }
                }

                while (i < left.length) {
                    result.push(left[i]);
                    i++;
                }
                while (j < right.length) {
                    result.push(right[j]);
                    j++;
                }
                return result;
            }

            async function sort(currentArr, startIndex) {
                if (currentArr.length <= 1) {
                    return currentArr;
                }

                const mid = Math.floor(currentArr.length / 2);
                const left = currentArr.slice(0, mid);
                const right = currentArr.slice(mid);

                const sortedLeft = await sort(left, startIndex);
                const sortedRight = await sort(right, startIndex + mid);

                const merged = await merge(sortedLeft, sortedRight, startIndex);

                // Update the original array visually
                for (let k = 0; k < merged.length; k++) {
                    arr[startIndex + k] = merged[k];
                }
                renderChart(chartContainer, arr, [], Array.from({length: arr.length}, (_, i) => i)); // Render current state, no specific highlight during merge update
                stepsCounter.textContent = `Steps: ${steps}`;
                await new Promise(resolve => timeoutIds.push(setTimeout(resolve, animationDelay)));

                return merged;
            }

            await sort(arr, 0);
            renderChart(chartContainer, arr, [], Array.from({length: arr.length}, (_, i) => i)); // All sorted
            stepsCounter.textContent = `Steps: ${steps}`;
            return arr;
        }

        async function startComparison() {
            if (animationRunning) {
                clearTimeouts();
                animationRunning = false;
                startSortButton.textContent = "Start Comparison";
                // Re-initialize arrays and charts to clear previous state
                initializeCharts();
                return;
            }

            animationRunning = true;
            startSortButton.textContent = "Stop Comparison";
            clearTimeouts(); // Clear any existing timeouts from a previous run

            currentArraySize = parseInt(numElementsInput.value);
            animationDelay = 500 - parseInt(animationSpeedInput.value); // Invert speed for intuitive slider

            const originalArray = generateRandomArray(currentArraySize);

            // Reset step counters
            bubbleSortStepsCounter.textContent = 'Steps: 0';
            selectionSortStepsCounter.textContent = 'Steps: 0';
            mergeSortStepsCounter.textContent = 'Steps: 0';

            // Initial render
            renderChart(bubbleSortChart, originalArray);
            renderChart(selectionSortChart, originalArray);
            renderChart(mergeSortChart, originalArray);

            // Run algorithms concurrently
            await Promise.all([
                bubbleSort(originalArray, bubbleSortChart, bubbleSortStepsCounter),
                selectionSort(originalArray, selectionSortChart, selectionSortStepsCounter),
                mergeSort(originalArray, mergeSortChart, mergeSortStepsCounter)
            ]);

            animationRunning = false;
            startSortButton.textContent = "Start Comparison";
        }

        function initializeCharts() {
            const initialArray = generateRandomArray(parseInt(numElementsInput.value));
            renderChart(bubbleSortChart, initialArray);
            renderChart(selectionSortChart, initialArray);
            renderChart(mergeSortChart, initialArray);

            bubbleSortStepsCounter.textContent = 'Steps: 0';
            selectionSortStepsCounter.textContent = 'Steps: 0';
            mergeSortStepsCounter.textContent = 'Steps: 0';
        }

        // Event Listeners
        startSortButton.addEventListener('click', startComparison);
        numElementsInput.addEventListener('change', () => {
            if (!animationRunning) {
                initializeCharts();
            }
        });

        // Initial setup
        initializeCharts();
    </script>
</body>
</html>
