            background-color: #f0ad4e; /* Orange when swapped, still not great */
        }
        .bubble-sort-special .bar.comparing {
            background-color: #337ab7; /* Blue when comparing, like it's trying */
        }
        @media (max-width: 1200px) {
            .algorithm-card {
                width: calc(50% - 30px);
            }
        }
        @media (max-width: 768px) {
            .algorithm-card {
                width: 90%;
            }
            .controls {
                flex-direction: column;
            }
            button {
                margin-bottom: 10px;
            }
            #speedSlider {
                margin-top: 10px;
                margin-left: 0;
            }
        }
    </style>
</head>
<body>

    <h1>Sorting Algorithm Showdown: Bubble Sort's Demise</h1>
    <p style="text-align: center; font-size: 1.2em; color: #555;">Watch as Bubble Sort struggles against more efficient algorithms. Pay close attention to the step counters and the speed of sorting!</p>

    <div class="controls">
        <button id="startButton">Start Sorting!</button>
        <button id="resetButton">Reset</button>
        <label for="arraySize">Array Size:</label>
        <input type="number" id="arraySize" value="50" min="10" max="200" style="width: 60px;">
        <label for="speedSlider">Animation Speed:</label>
        <input type="range" id="speedSlider" min="1" max="500" value="100">
        <span id="speedValue">100 ms</span>
    </div>

    <div class="container" id="algorithmsContainer">
        <!-- Algorithm cards will be inserted here by JavaScript -->
    </div>

    <script>
        const ARRAY_MAX_VALUE = 200; // Max value for bars' height
        const algorithms = [];
        let animationSpeed = 100; // Milliseconds per step
        let isSorting = false;
        let originalArray = [];
        let arraySize = 50; // Default array size

        class AlgorithmVisualizer {
            constructor(name, sortFunction, complexity, description, isBubbleSort = false) {
                this.name = name;
                this.sortFunction = sortFunction;
                this.complexity = complexity;
                this.description = description;
                this.isBubbleSort = isBubbleSort;
                this.array = [];
                this.steps = 0;
                this.card = null;
                this.chartContainer = null;
                this.stepCounterElement = null;
                this.timeoutId = null;
                this.completed = false;
                this.initDOM();
            }

            initDOM() {
                this.card = document.createElement('div');
                this.card.classList.add('algorithm-card');
                if (this.isBubbleSort) {
                    this.card.classList.add('bubble-sort-special');
                }

                this.card.innerHTML = `
                    <h2>${this.name}</h2>
                    <div class="chart-container"></div>
                    <div class="info">
                        Steps: <span class="step-counter">0</span>
                    </div>
                    <div class="complexity">
                        <span><strong>Time Complexity (Worst/Average):</strong> ${this.complexity.time}</span>
                        <span><strong>Space Complexity (Worst):</strong> ${this.complexity.space}</span>
                    </div>
                    <p class="description">${this.description}</p>
                `;
                document.getElementById('algorithmsContainer').appendChild(this.card);

                this.chartContainer = this.card.querySelector('.chart-container');
                this.stepCounterElement = this.card.querySelector('.step-counter');
            }

            reset(newArray) {
                clearTimeout(this.timeoutId);
                this.array = [...newArray];
                this.steps = 0;
                this.completed = false;
                this.updateDisplay();
            }

            updateDisplay(comparing = [], swapped = [], pivot = []) {
                this.chartContainer.innerHTML = '';
                const maxValue = Math.max(...this.array); // Normalize based on current max value
                this.array.forEach((value, index) => {
                    const bar = document.createElement('div');
                    bar.classList.add('bar');
                    // Scale height relative to the max possible value (ARRAY_MAX_VALUE)
                    bar.style.height = `${(value / ARRAY_MAX_VALUE) * 100}%`;

                    if (comparing.includes(index)) {
                        bar.classList.add('comparing');
                    }
                    if (swapped.includes(index)) {
                        bar.classList.add('swapped');
                    }
                    if (pivot.includes(index)) {
                        bar.classList.add('pivot');
                    }
                     // Mark sorted elements if the algorithm is complete
                    if (this.completed) {
                        bar.classList.add('sorted');
                    }
                    this.chartContainer.appendChild(bar);
                });
                this.stepCounterElement.textContent = this.steps;
            }

            async startSorting() {
                if (this.completed) return; // Don't re-sort if already done

                // This allows algorithms to yield control back to the event loop
                // and for animations to render without blocking.
                const delay = (ms) => new Promise(resolve => this.timeoutId = setTimeout(resolve, ms));

                // Pass the delay function to the sort algorithm so it can animate
                await this.sortFunction(this.array, this, delay);
                this.completed = true;
                this.updateDisplay(); // Final display update with all bars marked sorted
            }
        }

        // --- Sorting Algorithms ---

        async function bubbleSort(arr, visualizer, delay) {
            const n = arr.length;
            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - 1 - i; j++) {
                    visualizer.steps++;
                    visualizer.updateDisplay([j, j + 1]);
                    await delay(animationSpeed);

                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                        visualizer.updateDisplay([j, j + 1], [j, j + 1]); // Mark as swapped
                        await delay(animationSpeed);
                    }
                }
                // Mark the last 'i' elements as sorted (they are in their final position)
                visualizer.updateDisplay([], [], [], Array.from({length: i + 1}, (_, k) => n - 1 - k));
            }
        }

        async function selectionSort(arr, visualizer, delay) {
            const n = arr.length;
            for (let i = 0; i < n - 1; i++) {
                let minIdx = i;
                visualizer.updateDisplay([], [], [i]); // Mark current 'i' as potentially sorted boundary

                for (let j = i + 1; j < n; j++) {
                    visualizer.steps++;
                    visualizer.updateDisplay([minIdx, j], [], [i]); // Compare current min with j
                    await delay(animationSpeed);

                    if (arr[j] < arr[minIdx]) {
                        minIdx = j;
                        visualizer.updateDisplay([], [], [i, minIdx]); // Update minIdx, highlight new min
                        await delay(animationSpeed);
                    }
                }

                if (minIdx !== i) {
                    [arr[i], arr[minIdx]] = [arr[minIdx], arr[i]];
                    visualizer.updateDisplay([i, minIdx], [i, minIdx]); // Mark as swapped
                    await delay(animationSpeed);
                }
                // Mark 'i' as sorted
                visualizer.updateDisplay([], [], [], Array.from({length: i + 1}, (_, k) => k));
            }
        }

        async function mergeSort(arr, visualizer, delay) {
            async function merge(left, right, originalStartIndex) {
                let result = [];
                let leftIndex = 0;
                let rightIndex = 0;

                while (leftIndex < left.length && rightIndex < right.length) {
                    visualizer.steps++;
                    // Simulate comparison for animation
                    visualizer.updateDisplay(
                        [originalStartIndex + leftIndex, originalStartIndex + left.length + rightIndex]
                    );
                    await delay(animationSpeed / 2); // Faster comparison within merge

                    if (left[leftIndex] < right[rightIndex]) {
                        result.push(left[leftIndex]);
                        leftIndex++;
                    } else {
                        result.push(right[rightIndex]);
                        rightIndex++;
                    }
                }
                return result.concat(left.slice(leftIndex)).concat(right.slice(rightIndex));
            }

            async function sort(currentArr, startIndex) {
                if (currentArr.length <= 1) {
                    return currentArr;
                }

                const middle = Math.floor(currentArr.length / 2);
                const left = currentArr.slice(0, middle);
                const right = currentArr.slice(middle);

                const sortedLeft = await sort(left, startIndex);
                const sortedRight = await sort(right, startIndex + middle);

                const merged = await merge(sortedLeft, sortedRight, startIndex);

                // Update the main array with the merged result
                for (let i = 0; i < merged.length; i++) {
                    arr[startIndex + i] = merged[i];
                }

                visualizer.updateDisplay(Array.from({length: merged.length}, (_, i) => startIndex + i), [], [], Array.from({length: merged.length}, (_, i) => startIndex + i));
                await delay(animationSpeed); // Delay after each merge step
                return merged;
            }

            await sort(arr, 0);
        }


        // --- Initialization and Event Listeners ---

        function generateRandomArray(size) {
            return Array.from({ length: size }, () => Math.floor(Math.random() * ARRAY_MAX_VALUE) + 1);
        }

        function setupAlgorithms() {
            algorithms.push(new AlgorithmVisualizer(
                "Bubble Sort (The 'Greatest')",
                bubbleSort,
                { time: "O(n²)", space: "O(1)" },
                "Compares adjacent elements and swaps them if they are in the wrong order. Repeats until no swaps are needed. Extremely inefficient for large datasets.",
                true // Mark as bubble sort for special styling
            ));
            algorithms.push(new AlgorithmVisualizer(
                "Selection Sort",
                selectionSort,
                { time: "O(n²)", space: "O(1)" },
                "Finds the minimum element from the unsorted part and puts it at the beginning. Simple but also inefficient for large datasets, though generally performs fewer swaps than Bubble Sort.",
            ));
            algorithms.push(new AlgorithmVisualizer(
                "Merge Sort",
                mergeSort,
                { time: "O(n log n)", space: "O(n)" },
                "A divide-and-conquer algorithm. It divides the unsorted list into n sublists, each containing one element, and then repeatedly merges sublists to produce new sorted sublists until there is only one sublist remaining. Highly efficient!",
            ));
            // Add more algorithms if you want! E.g., Quick Sort, Heap Sort
            /*
            algorithms.push(new AlgorithmVisualizer(
                "Quick Sort",
                quickSort, // You would need to implement quickSort async function
                { time: "O(n log n) average, O(n²) worst", space: "O(log n) average, O(n) worst" },
                "Picks an element as a pivot and partitions the given array around the picked pivot. Recursive and very fast in practice, but worst-case can be slow."
            ));
            */
        }

        function initialize() {
            originalArray = generateRandomArray(arraySize);
            algorithms.forEach(algo => algo.reset(originalArray));
            isSorting = false;
            document.getElementById('startButton').textContent = 'Start Sorting!';
            document.getElementById('startButton').disabled = false;
        }

        document.getElementById('startButton').addEventListener('click', async () => {
            if (isSorting) return;
            isSorting = true;
            document.getElementById('startButton').textContent = 'Sorting...';
            document.getElementById('startButton').disabled = true;

            // Start all algorithms concurrently
            const sortPromises = algorithms.map(algo => algo.startSorting());
            await Promise.all(sortPromises);

            isSorting = false;
            document.getElementById('startButton').textContent = 'All Sorted!';
        });

        document.getElementById('resetButton').addEventListener('click', () => {
            initialize();
        });

        document.getElementById('speedSlider').addEventListener('input', (event) => {
            animationSpeed = 500 - parseInt(event.target.value) + 1; // Invert slider for intuitive speed
            document.getElementById('speedValue').textContent = `${500 - animationSpeed + 1} ms`;
        });

        document.getElementById('arraySize').addEventListener('change', (event) => {
            let newSize = parseInt(event.target.value);
            if (isNaN(newSize) || newSize < 10) newSize = 10;
            if (newSize > 200) newSize = 200; // Cap to prevent UI overload
            arraySize = newSize;
            event.target.value = arraySize; // Update input if it was out of bounds
            initialize();
        });

        // Initial setup
        setupAlgorithms();
        initialize();

    </script>
</body>
</html>
```

### How to Use:

1.  **Save:** Copy the entire code block above and paste it into a file named `sorting_showdown.html`.
2.  **Open:** Open `sorting_showdown.html` in your web browser (Chrome, Firefox, Edge, etc.).
3.  **Observe:**
    *   Click "Start Sorting!".
    *   Watch the bar charts animate.
    *   Pay close attention to the "Steps" counter for each algorithm.
    *   You'll immediately see Bubble Sort making many, many more comparisons and swaps compared to Merge Sort, even Selection Sort will likely finish faster on larger datasets.
    *   Adjust the "Animation Speed" and "Array Size" to emphasize the differences. A larger array size will make Bubble Sort's inefficiency *painfully* clear.

### Key Features and Why it Humiliates Bubble Sort:

*   **Side-by-Side Comparison:** All algorithms sort the *exact same initial random data* simultaneously. This is crucial for a fair comparison.
*   **Animated Bar Charts:** Visual representation of the data. Bars change color when being compared or swapped, making the process clear.
*   **Step Counters:** Explicitly shows the number of operations (comparisons/swaps) each algorithm performs. Bubble Sort's counter will skyrocket.
*   **Complexity Notes:** Big O notation for Time and Space complexity is displayed, providing the theoretical backing for the visual demonstration.
*   **Bubble Sort Highlight:** Bubble Sort's card has a distinct red background and border to visually emphasize its "special" (read: inferior) status. Its bars also start red.
*   **Speed and Array Size Controls:** You can adjust these to make the humiliation even more stark. A large array size (e.g., 200 elements) at a moderate speed will fully expose Bubble Sort.
*   **Clear Descriptions:** Explains briefly how each algorithm works.

This should give your colleague a very clear, undeniable, and *animated* visual lesson on why Bubble Sort is, in fact, **not** the greatest sorting algorithm ever invented. Enjoy the vindication!
